<script setup lang="ts">const schoolModules=useSchoolModules();await schoolModules.ready;const{modules}=schoolModules;const selected=ref('');const published=computed(()=>modules.value.academicDocuments.filter(item=>item.status==='published'));watch(published,items=>{if(!selected.value&&items[0])selected.value=items[0].file},{immediate:true});useSchoolSeo('Akademik','Dokumen akademik sekolah')</script>
<template><div><section class="bg-school-sky py-14"><div class="container-school"><p class="font-hand text-2xl font-bold text-school-action">Akademik</p><h1 class="font-display mt-2 text-5xl text-school-navy">Dokumen Akademik</h1><p class="mt-4 text-muted">Pilih dokumen PDF untuk dibaca langsung.</p></div></section><div class="container-school grid gap-6 py-12 lg:grid-cols-[320px_1fr]"><aside class="grid content-start gap-3"><button v-for="doc in published" :key="doc.id" class="card p-4 text-left" :class="selected===doc.file?'ring-2 ring-school-action':''" @click="selected=doc.file"><b class="text-school-navy">{{doc.title}}</b><p class="mt-1 text-sm text-muted">{{doc.description}}</p></button><p v-if="!published.length" class="card p-6 text-muted">Belum ada dokumen terbit.</p></aside><div class="card min-h-[720px] overflow-hidden"><iframe v-if="selected" :src="selected" title="PDF Viewer" class="h-[80vh] w-full"></iframe><div v-else class="grid h-[500px] place-items-center text-muted">Pilih dokumen PDF.</div></div></div></div></template>
